public void testParameter5() {
  // Test with single parameter - should allow coalescing
  test("function FUNC(x) {var a,b; x; a=0; a; b=0; b}",
       "function FUNC(x) {var a; x; a=0; a; a=0; a}");
}

public void testParameter6() {
  // Test with three parameters - should not coalesce to avoid IE bug
  test("function FUNC(x, y, z) {var a,b; x; y; z; a=0; a; b=0; b}",
       "function FUNC(x, y, z) {var a; x; y; z; a=0; a; a=0; a}");
}

public void testParseLicenseWithMultipleAnnotations() throws Exception {
  Node node = new Node(1);
  this.fileLevelJsDocBuilder = node.getJsDocBuilderForNode();
  String comment = "@license Foo \n * @author Charlie Brown \n * @version 1.0 */";
  parse(comment);
  assertEquals(" Foo \n @author Charlie Brown \n @version 1.0 ",
      node.getJSDocInfo().getLicense());
}

public void testParseLicenseWithAnnotationAtStart() throws Exception {
  Node node = new Node(1);
  this.fileLevelJsDocBuilder = node.getJsDocBuilderForNode();
  String comment = "@license @author Charlie Brown \n * Some text */";
  parse(comment);
  assertEquals(" @author Charlie Brown \n Some text ",
      node.getJSDocInfo().getLicense());
}
